        !targetElement ||
        targetElement === templateEditorSurface ||
        !templateEditorSurface.contains(targetElement) ||
        /^(P|DIV|LI|UL|OL|H1|H2|H3|H4|H5|H6|BLOCKQUOTE|TD|TH|TR|TBODY|THEAD|TFOOT|TABLE)$/i.test(targetElement.tagName || "")
