        const coveringEntry = coveringCell ? entries.get(coveringCell) : null;

        if (!coveringEntry || adjustedCells.has(coveringCell)) {
          return;
        }

        coveringCell.colSpan = coveringEntry.colSpan + addedColumnCount;
