      const startElement =
        range.startContainer instanceof ownerWindow.Element
          ? range.startContainer
          : range.startContainer?.parentElement || null;
      const endElement =
        range.endContainer instanceof ownerWindow.Element
          ? range.endContainer
          : range.endContainer?.parentElement || null;

